import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import type { Geolocation as GeoType } from '../types';
import { MapPin, User, Phone, Home, Loader2, CheckCircle } from 'lucide-react';

const LoginScreen: React.FC = () => {
  const { login } = useAuth();
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [location, setLocation] = useState<GeoType | null>(null);
  const [isGettingLocation, setIsGettingLocation] = useState(false);
  const [locationError, setLocationError] = useState('');

  const handleGetLocation = () => {
    setIsGettingLocation(true);
    setLocationError('');
    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          latitude: position.coords.latitude,
          longitude: position.coords.longitude,
        });
        setIsGettingLocation(false);
      },
      (error) => {
        setLocationError('Could not get location. Please enable permissions and try again.');
        setIsGettingLocation(false);
      }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (name && phone && address && location) {
      // In a real app, OTP verification would happen here.
      // We'll simulate a successful login.
      login({ name, phone, address, location });
    } else {
      alert('Please fill all fields and provide your location.');
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white p-8 rounded-2xl shadow-lg">
      <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Welcome! Let's get you set up.</h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="relative">
            <User className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400"/>
            <input
            type="text"
            placeholder="Your Name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg shadow-sm focus:ring-amber-500 focus:border-amber-500 transition"
            />
        </div>
        <div className="relative">
            <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400"/>
            <input
            type="tel"
            placeholder="Phone Number (for OTP)"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            required
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg shadow-sm focus:ring-amber-500 focus:border-amber-500 transition"
            />
        </div>
        <div className="relative">
            <Home className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400"/>
            <input
            type="text"
            placeholder="Delivery Address"
            value={address}
            onChange={(e) => setAddress(e.target.value)}
            required
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg shadow-sm focus:ring-amber-500 focus:border-amber-500 transition"
            />
        </div>
        <div>
          <button
            type="button"
            onClick={handleGetLocation}
            disabled={isGettingLocation || !!location}
            className="w-full flex justify-center items-center py-2 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition"
          >
            {isGettingLocation ? (
              <Loader2 className="h-5 w-5 mr-2 animate-spin" />
            ) : location ? (
              <CheckCircle className="h-5 w-5 mr-2" />
            ) : (
              <MapPin className="h-5 w-5 mr-2" />
            )}
            {isGettingLocation ? 'Fetching Location...' : location ? 'Location Pinned!' : 'Pin Your Exact Location'}
          </button>
          {locationError && <p className="text-red-500 text-xs mt-2">{locationError}</p>}
        </div>
        <button
          type="submit"
          disabled={!name || !phone || !address || !location}
          className="w-full py-3 px-4 border border-transparent rounded-lg shadow-sm text-base font-medium text-white bg-amber-600 hover:bg-amber-700 disabled:bg-amber-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-amber-500 transition"
        >
          Register & Continue
        </button>
      </form>
    </div>
  );
};

