import React, { useState } from 'react';
import { useCart } from '../context/CartContext';
import { useSettings } from '../context/SettingsContext';
import { useAuth } from '../context/AuthContext';
import { X, Trash2, Plus, Minus, Send } from 'lucide-react';
import { WHATSAPP_NUMBER, RESTAURANT_NAME } from '../constants';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const CartModal: React.FC<CartModalProps> = ({ isOpen, onClose }) => {
  const { cart, removeFromCart, updateQuantity, cartTotal, clearCart } = useCart();
  const { settings } = useSettings();
  const { user } = useAuth();
  const [instructions, setInstructions] = useState('');

  if (!isOpen) return null;

  const discountAmount = (cartTotal * settings.discountPercent) / 100;
  const grandTotal = cartTotal - discountAmount + settings.packagingCharge + settings.deliveryCharge;

  const handlePlaceOrder = () => {
    if (!user) {
      alert("User not logged in.");
      return;
    }

    const orderDetails = cart.map(item => `${item.name} (x${item.quantity}) - ₹${(item.price * item.quantity).toFixed(2)}`).join('\n');
    const locationLink = user.location ? `https://www.google.com/maps?q=${user.location.latitude},${user.location.longitude}` : 'Not provided';

    const message = `
*New Order from ${RESTAURANT_NAME} App*

*Customer Details:*
Name: ${user.name}
Phone: ${user.phone}
Address: ${user.address}

*Order Items:*
${orderDetails}

*Preparation Instructions:*
${instructions || 'None'}

-----------------------------------
Subtotal: ₹${cartTotal.toFixed(2)}
Discount (${settings.discountPercent}%): -₹${discountAmount.toFixed(2)}
Packaging Charge: +₹${settings.packagingCharge.toFixed(2)}
Delivery Charge: +₹${settings.deliveryCharge.toFixed(2)}
-----------------------------------
*Grand Total: ₹${grandTotal.toFixed(2)}*

*Delivery Location:*
${locationLink}
    `;

    const whatsappUrl = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(message.trim())}`;
