import React, { createContext, useContext } from 'react';
import useLocalStorage from '../hooks/useLocalStorage';
import type { MenuItem } from '../types';
import { INITIAL_MENU } from '../constants';

interface MenuContextType {
  menu: MenuItem[];
  addMenuItem: (item: Omit<MenuItem, 'id' | 'isOutOfStock'>) => void;
  deleteMenuItem: (id: number) => void;
  toggleStock: (id: number) => void;
}

const MenuContext = createContext<MenuContextType | undefined>(undefined);

export const MenuProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [menu, setMenu] = useLocalStorage<MenuItem[]>('rannaghar_menu', INITIAL_MENU);

  const addMenuItem = (item: Omit<MenuItem, 'id' | 'isOutOfStock'>) => {
    setMenu(prev => [
      ...prev,
      {
        ...item,
        id: Date.now(), // simple unique id
        isOutOfStock: false,
      },
    ]);
  };

  const deleteMenuItem = (id: number) => {
    setMenu(prev => prev.filter(item => item.id !== id));
  };

  const toggleStock = (id: number) => {
    setMenu(prev =>
      prev.map(item =>
        item.id === id ? { ...item, isOutOfStock: !item.isOutOfStock } : item
      )
    );
  };

  return (
    <MenuContext.Provider value={{ menu, addMenuItem, deleteMenuItem, toggleStock }}>
      {children}
    </MenuContext.Provider>
  );
};

export const useMenu = (): MenuContextType => {
  const context = useContext(MenuContext);
  if (context === undefined) {
    throw new Error('useMenu must be used within a MenuProvider');
  }
  return context;
};

import React, { createContext, useContext } from 'react';
import useLocalStorage from '../hooks/useLocalStorage';
import type { Order, CartItem, User } from '../types';

interface OrderContextType {
  orders: Order[];
  addOrder: (orderData: { items: CartItem[]; totalAmount: number; customer: User }) => void;
}

const OrderContext = createContext<OrderContextType | undefined>(undefined);

export const OrderProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [orders, setOrders] = useLocalStorage<Order[]>('rannaghar_orders', []);

  const addOrder = (orderData: { items: CartItem[]; totalAmount: number; customer: User }) => {
    const newOrder: Order = {
      ...orderData,
      id: `order_${Date.now()}`,
      timestamp: Date.now(),
    };
    setOrders(prev => [...prev, newOrder]);
  };

  return (
    <OrderContext.Provider value={{ orders, addOrder }}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrders = (): OrderContextType => {
  const context = useContext(OrderContext);
  if (context === undefined) {
    throw new Error('useOrders must be used within an OrderProvider');
  }
  return context;
};

