import { useOrders } from '../context/OrderContext';
import { X, Trash2, Plus, Minus, Send } from 'lucide-react';
import { WHATSAPP_NUMBER, RESTAURANT_NAME } from '../constants';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const CartModal: React.FC<CartModalProps> = ({ isOpen, onClose }) => {
  const { cart, removeFromCart, updateQuantity, cartTotal, clearCart } = useCart();
  const { settings } = useSettings();
  const { user } = useAuth();
  const { addOrder } = useOrders();
  const [instructions, setInstructions] = useState('');

  if (!isOpen) return null;

  const discountAmount = (cartTotal * settings.discountPercent) / 100;
  const grandTotal = cartTotal - discountAmount + settings.packagingCharge + settings.deliveryCharge;

  const handlePlaceOrder = () => {
    if (!user) {
      alert("User not logged in.");
      return;
    }

    // Save order for reporting
    addOrder({
        customer: user,
        items: cart,
        totalAmount: grandTotal
    });

    const orderDetails = cart.map(item => `${item.name} (x${item.quantity}) - ₹${(item.price * item.quantity).toFixed(2)}`).join('\n');
    const locationLink = user.location ? `https://www.google.com/maps?q=${user.location.latitude},${user.location.longitude}` : 'Not provided';

    const message = `
*New Order from ${RESTAURANT_NAME} App*

*Customer Details:*
Name: ${user.name}
Phone: ${user.phone}
Address: ${user.address}

*Order Items:*
${orderDetails}

*Preparation Instructions:*
${instructions || 'None'}

-----------------------------------
Subtotal: ₹${cartTotal.toFixed(2)}
Discount (${settings.discountPercent}%): -₹${discountAmount.toFixed(2)}
Packaging Charge: +₹${settings.packagingCharge.toFixed(2)}
Delivery Charge: +₹${settings.deliveryCharge.toFixed(2)}
-----------------------------------
*Grand Total: ₹${grandTotal.toFixed(2)}*

*Delivery Location:*
${locationLink}
    `;

    const whatsappUrl = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(message.trim())}`;
    window.open(whatsappUrl, '_blank');
    clearCart();
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg max-h-[90vh] flex flex-col transform transition-all duration-300 ease-out scale-95 animate-scale-in">
        <header className="flex justify-between items-center p-5 border-b">
          <h2 className="text-2xl font-bold text-gray-800">Your Order</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-gray-800 transition-colors">
            <X className="h-7 w-7" />
          </button>
        </header>

        <main className="flex-grow overflow-y-auto p-5 space-y-4">
          {cart.length === 0 ? (
            <p className="text-center text-gray-500 py-8">Your cart is empty.</p>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex items-center space-x-4">
                <img src={item.image} alt={item.name} className="w-20 h-20 rounded-lg object-cover" />
                <div className="flex-grow">
                  <p className="font-semibold text-gray-800">{item.name}</p>
                  <p className="text-sm text-gray-600">₹{item.price}</p>
                </div>
                <div className="flex items-center border rounded-lg">
                  <button onClick={() => updateQuantity(item.id, item.quantity - 1)} className="p-2 text-gray-600 hover:text-red-500"><Minus size={16} /></button>
                  <span className="px-3 font-medium">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, item.quantity + 1)} className="p-2 text-gray-600 hover:text-green-500"><Plus size={16} /></button>
                </div>
                <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={20} /></button>
              </div>
            ))
          )}
          {cart.length > 0 && (
             <div className="pt-4">
                <label htmlFor="instructions" className="block text-sm font-medium text-gray-700 mb-1">Food Preparation Instructions</label>
                <textarea
                    id="instructions"
                    value={instructions}
                    onChange={(e) => setInstructions(e.target.value)}
                    rows={3}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg shadow-sm focus:ring-amber-500 focus:border-amber-500 transition"
                    placeholder="e.g., Make it extra spicy, no onions..."
                ></textarea>
            </div>
          )}
        </main>

        {cart.length > 0 && (
          <footer className="p-5 border-t bg-gray-50 rounded-b-2xl">
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between"><span>Subtotal</span><span>₹{cartTotal.toFixed(2)}</span></div>
              <div className="flex justify-between text-red-600"><span>Discount ({settings.discountPercent}%)</span><span>- ₹{discountAmount.toFixed(2)}</span></div>
              <div className="flex justify-between"><span>Packaging</span><span>+ ₹{settings.packagingCharge.toFixed(2)}</span></div>
              <div className="flex justify-between"><span>Delivery</span><span>+ ₹{settings.deliveryCharge.toFixed(2)}</span></div>
              <div className="flex justify-between text-xl font-bold pt-2 border-t mt-2"><span>Total</span><span>₹{grandTotal.toFixed(2)}</span></div>
            </div>
            <button 
                onClick={handlePlaceOrder}
                className="w-full mt-4 flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-base font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-colors duration-300"
            >
              <Send className="h-5 w-5 mr-2" />
              Place Order on WhatsApp
            </button>
          </footer>
        )}
      </div>
       <style>{`
        @keyframes scale-in {
          from { transform: scale(0.95); opacity: 0; }
          to { transform: scale(1); opacity: 1; }
        }
        .animate-scale-in { animation: scale-in 0.2s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default CartModal;

import React, { createContext, useContext, useState } from 'react';
import useLocalStorage from '../hooks/useLocalStorage';
import type { User } from '../types';

interface AuthContextType {
  user: User | null;
  login: (phone: string) => boolean;
  signup: (userData: Omit<User, 'location'> & { location: NonNullable<User['location']> }) => { success: boolean, message: string };
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [users, setUsers] = useLocalStorage<User[]>('rannaghar_users', []);
  const [currentUser, setCurrentUser] = useLocalStorage<User | null>('rannaghar_currentUser', null);

  const login = (phone: string): boolean => {
    const userExists = users.find(u => u.phone === phone);
    if (userExists) {
      setCurrentUser(userExists);
      return true;
    }
    return false;
  };

  const signup = (userData: Omit<User, 'location'> & { location: NonNullable<User['location']> }): { success: boolean, message: string } => {
    const userExists = users.find(u => u.phone === userData.phone);
    if (userExists) {
        return { success: false, message: 'A user with this phone number already exists.' };
    }

    const newUser: User = { ...userData };
    setUsers(prevUsers => [...prevUsers, newUser]);
    setCurrentUser(newUser);
    return { success: true, message: 'Registration successful!' };
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const isAuthenticated = !!currentUser;

  return (
    <AuthContext.Provider value={{ user: currentUser, login, signup, logout, isAuthenticated }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import type { Geolocation as GeoType } from '../types';
import { MapPin, User, Phone, Home, Loader2, CheckCircle, LogIn, UserPlus } from 'lucide-react';

const LoginView = ({ onSwitchToSignUp }: { onSwitchToSignUp: () => void }) => {
  const { login } = useAuth();
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const success = login(phone);
    if (!success) {
      setError('No account found with this phone number. Please sign up.');
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Login to Rannaghar</h2>
      <form onSubmit={handleLogin} className="space-y-6">
        <div className="relative">
          <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input
            type="tel"
            placeholder="Enter your Phone Number"
            value={phone}
            onChange={(e) => {
              setPhone(e.target.value);
              setError('');
            }}
            required
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg shadow-sm focus:ring-amber-500 focus:border-amber-500 transition"
          />
        </div>
        {error && <p className="text-red-500 text-sm text-center">{error}</p>}
        <button
          type="submit"
          className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-base font-medium text-white bg-amber-600 hover:bg-amber-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-amber-500 transition"
        >
          <LogIn className="mr-2 h-5 w-5"/>
          Login with OTP
        </button>
      </form>
      <p className="text-center text-sm text-gray-600 mt-6">
        Don't have an account?{' '}
        <button onClick={onSwitchToSignUp} className="font-semibold text-indigo-600 hover:text-indigo-500">
          Sign Up
        </button>
      </p>
    </div>
  );
};

const SignUpView = ({ onSwitchToLogin }: { onSwitchToLogin: () => void }) => {
  const { signup } = useAuth();
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [location, setLocation] = useState<GeoType | null>(null);
  const [isGettingLocation, setIsGettingLocation] = useState(false);
  const [locationError, setLocationError] = useState('');
  const [signupError, setSignupError] = useState('');

  const handleGetLocation = () => {
    setIsGettingLocation(true);
    setLocationError('');
    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          latitude: position.coords.latitude,
          longitude: position.coords.longitude,
        });
        setIsGettingLocation(false);
      },
      (error) => {
        setLocationError('Could not get location. Please enable permissions and try again.');
        setIsGettingLocation(false);
      }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSignupError('');
    if (name && phone && address && location) {
      const result = signup({ name, phone, address, location });
      if (!result.success) {
          setSignupError(result.message);
      }
    } else {
      alert('Please fill all fields and provide your location.');
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Create Your Account</h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="relative">
          <User className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input type="text" placeholder="Your Name" value={name} onChange={(e) => setName(e.target.value)} required className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-amber-500 focus:border-amber-500"/>
        </div>
        <div className="relative">
          <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input type="tel" placeholder="Phone Number" value={phone} onChange={(e) => setPhone(e.target.value)} required className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-amber-500 focus:border-amber-500"/>
        </div>
        <div className="relative">
          <Home className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input type="text" placeholder="Delivery Address" value={address} onChange={(e) => setAddress(e.target.value)} required className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-amber-500 focus:border-amber-500"/>
        </div>
        <div>
          <button type="button" onClick={handleGetLocation} disabled={isGettingLocation || !!location} className="w-full flex justify-center items-center py-2 px-4 border rounded-lg text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300">
            {isGettingLocation ? <Loader2 className="h-5 w-5 mr-2 animate-spin" /> : location ? <CheckCircle className="h-5 w-5 mr-2" /> : <MapPin className="h-5 w-5 mr-2" />}
            {isGettingLocation ? 'Fetching...' : location ? 'Location Pinned!' : 'Pin Your Location'}
          </button>
          {locationError && <p className="text-red-500 text-xs mt-2">{locationError}</p>}
        </div>
        {signupError && <p className="text-red-500 text-sm text-center">{signupError}</p>}
        <button type="submit" disabled={!name || !phone || !address || !location} className="w-full flex justify-center items-center py-3 px-4 border rounded-lg text-base font-medium text-white bg-amber-600 hover:bg-amber-700 disabled:bg-amber-300">
            <UserPlus className="mr-2 h-5 w-5" />
            Sign Up & Continue
        </button>
      </form>
      <p className="text-center text-sm text-gray-600 mt-6">
        Already have an account?{' '}
        <button onClick={onSwitchToLogin} className="font-semibold text-indigo-600 hover:text-indigo-500">
          Login
        </button>
      </p>
    </div>
  );
};


const LoginScreen: React.FC = () => {
    const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');

    return (
        <div className="max-w-md mx-auto bg-white p-8 rounded-2xl shadow-lg">
            {authMode === 'login' ? (
                <LoginView onSwitchToSignUp={() => setAuthMode('signup')} />
            ) : (
                <SignUpView onSwitchToLogin={() => setAuthMode('login')} />
            )}
        </div>
    )
}

export default LoginScreen;

import React, { createContext, useContext } from 'react';
import useLocalStorage from '../hooks/useLocalStorage';
import type { MenuItem } from '../types';
import { INITIAL_MENU } from '../constants';

interface MenuContextType {
  menu: MenuItem[];
  addMenuItem: (item: Omit<MenuItem, 'id' | 'isOutOfStock'>) => void;
  deleteMenuItem: (id: number) => void;
  updateMenuItem: (id: number, data: Partial<Omit<MenuItem, 'id'>>) => void;
  toggleStock: (id: number) => void;
}

const MenuContext = createContext<MenuContextType | undefined>(undefined);

export const MenuProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [menu, setMenu] = useLocalStorage<MenuItem[]>('rannaghar_menu', INITIAL_MENU);

  const addMenuItem = (item: Omit<MenuItem, 'id' | 'isOutOfStock'>) => {
    setMenu(prev => [
      ...prev,
      {
        ...item,
        id: Date.now(), // simple unique id
        isOutOfStock: false,
      },
    ]);
  };

  const updateMenuItem = (id: number, data: Partial<Omit<MenuItem, 'id'>>) => {
    setMenu(prev =>
      prev.map(item =>
        item.id === id ? { ...item, ...data } : item
      )
    );
  };

  const deleteMenuItem = (id: number) => {
    setMenu(prev => prev.filter(item => item.id !== id));
  };

  const toggleStock = (id: number) => {
    setMenu(prev =>
      prev.map(item =>
        item.id === id ? { ...item, isOutOfStock: !item.isOutOfStock } : item
      )
    );
  };

  return (
    <MenuContext.Provider value={{ menu, addMenuItem, deleteMenuItem, updateMenuItem, toggleStock }}>
      {children}
    </MenuContext.Provider>
  );
};

export const useMenu = (): MenuContextType => {
  const context = useContext(MenuContext);
  if (context === undefined) {
    throw new Error('useMenu must be used within a MenuProvider');
  }
  return context;
};

