                        <span className="text-2xl font-bold text-blue-600">{orders.length}</span>
                    </div>
                </div>
            </div>
        </div>

        <div className="lg:col-span-2 space-y-8">
            <div className="bg-white p-6 rounded-2xl shadow-lg">
                 <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-semibold text-gray-700 flex items-center"><BookOpen className="mr-2 h-5 w-5 text-green-600"/>Manage Menu</h2>
                    <button onClick={() => setShowAddForm(!showAddForm)} className="flex items-center text-sm font-semibold text-indigo-600 hover:text-indigo-800"><Plus className="h-4 w-4 mr-1"/>{showAddForm ? 'Cancel' : 'Add New Item'}</button>
                 </div>

                {showAddForm && (
                    <form onSubmit={handleAddMenuItem} className="p-4 bg-gray-50 rounded-lg mb-4 space-y-3">
                        <input type="text" name="name" value={newItem.name} onChange={handleNewItemChange} placeholder="Item Name" required className="w-full p-2 border rounded-md"/>
                        <input type="text" name="description" value={newItem.description} onChange={handleNewItemChange} placeholder="Description" className="w-full p-2 border rounded-md"/>
                        <div className="grid grid-cols-2 gap-4">
                            <input type="number" name="price" value={newItem.price} onChange={handleNewItemChange} placeholder="Price" required className="w-full p-2 border rounded-md"/>
                            <input type="text" name="category" value={newItem.category} onChange={handleNewItemChange} placeholder="Category" required className="w-full p-2 border rounded-md"/>
                        </div>
                        <input type="text" name="image" value={newItem.image} onChange={handleNewItemChange} placeholder="Image URL (optional)" className="w-full p-2 border rounded-md"/>
                        <button type="submit" className="w-full py-2 text-white bg-green-600 hover:bg-green-700 rounded-md font-semibold">Add Item</button>
                    </form>
                )}

                <div className="space-y-2 max-h-96 overflow-y-auto pr-2">
                    {menu.map(item => (
                        <div key={item.id} className="flex items-center p-2 rounded-lg hover:bg-gray-50">
                            <div className="flex-grow">
                                <p className="font-semibold">{item.name} <span className="text-xs text-gray-500">({item.category})</span></p>
                                <p className="text-sm text-gray-600">₹{item.price}</p>
                            </div>
                            <button onClick={() => toggleStock(item.id)} className={`mr-2 text-xs font-semibold px-2 py-1 rounded-full ${item.isOutOfStock ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                                {item.isOutOfStock ? 'Stock Out' : 'In Stock'}
                            </button>
                            <button onClick={() => setEditingItem(item)} className="p-1 text-gray-400 hover:text-blue-600"><Edit size={18} /></button>
                            <button onClick={() => deleteMenuItem(item.id)} className="p-1 text-gray-400 hover:text-red-600"><Trash2 size={18} /></button>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-white p-6 rounded-2xl shadow-lg">
                <h2 className="text-xl font-semibold text-gray-700 mb-4">Recent Orders</h2>
                <div className="space-y-3 max-h-96 overflow-y-auto pr-2">
                    {orders.length > 0 ? [...orders].reverse().map(order => (
                        <div key={order.id} className="p-3 bg-gray-50 rounded-lg">
                            <div className="flex justify-between items-start">
                                <div>
                                    <p className="font-semibold">{order.customer.name}</p>
                                    <p className="text-xs text-gray-500">{new Date(order.timestamp).toLocaleString()}</p>
                                </div>
                                <p className="font-bold text-lg">₹{order.totalAmount.toFixed(2)}</p>
                            </div>
                            <ul className="text-sm text-gray-600 mt-2 list-disc list-inside">
                                {order.items.map(item => <li key={item.id}>{item.name} x {item.quantity}</li>)}
                            </ul>
                        </div>
                    )) : <p className="text-center text-gray-500 py-4">No orders yet.</p>}
                </div>
            </div>
        </div>
      </div>
      {editingItem && (
        <EditMenuItemModal 
            item={editingItem}
            onSave={handleUpdateMenuItem}
            onCancel={() => setEditingItem(null)}
        />
      )}
    </div>
  );
};

export default AdminView;

