import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import type { Geolocation as GeoType } from '../types';
import { MapPin, User, Phone, Home, Loader2, CheckCircle, LogIn, UserPlus, ShieldCheck } from 'lucide-react';

const LoginView = ({ onSwitchToSignUp }: { onSwitchToSignUp: () => void }) => {
  const { login } = useAuth();
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const success = login(phone);
    if (!success) {
      setError('No account found with this phone number. Please sign up.');
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Login to Rannaghar</h2>
      <form onSubmit={handleLogin} className="space-y-6">
        <div className="relative">
          <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input
            type="tel"
            placeholder="Enter your Phone Number"
            value={phone}
            onChange={(e) => {
              setPhone(e.target.value);
              setError('');
            }}
            required
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg shadow-sm focus:ring-amber-500 focus:border-amber-500 transition"
          />
        </div>
        {error && <p className="text-red-500 text-sm text-center">{error}</p>}
        <button
          type="submit"
          className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-base font-medium text-white bg-amber-600 hover:bg-amber-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-amber-500 transition"
        >
          <LogIn className="mr-2 h-5 w-5"/>
          Login with OTP
        </button>
      </form>
      <p className="text-center text-sm text-gray-600 mt-6">
        Don't have an account?{' '}
        <button onClick={onSwitchToSignUp} className="font-semibold text-indigo-600 hover:text-indigo-500">
          Sign Up
        </button>
      </p>
    </div>
  );
};

const SignUpView = ({ onSwitchToLogin }: { onSwitchToLogin: () => void }) => {
  const { signup } = useAuth();
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [location, setLocation] = useState<GeoType | null>(null);
  const [isGettingLocation, setIsGettingLocation] = useState(false);
  const [locationError, setLocationError] = useState('');
  const [signupError, setSignupError] = useState('');

  const handleGetLocation = () => {
    setIsGettingLocation(true);
    setLocationError('');
    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          latitude: position.coords.latitude,
          longitude: position.coords.longitude,
        });
        setIsGettingLocation(false);
      },
      (error) => {
        setLocationError('Could not get location. Please enable permissions and try again.');
        setIsGettingLocation(false);
      }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSignupError('');
    if (name && phone && address && location) {
      const result = signup({ name, phone, address, location });
      if (!result.success) {
          setSignupError(result.message);
      }
    } else {
      alert('Please fill all fields and provide your location.');
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">Create Your Account</h2>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="relative">
          <User className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input type="text" placeholder="Your Name" value={name} onChange={(e) => setName(e.target.value)} required className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-amber-500 focus:border-amber-500"/>
        </div>
        <div className="relative">
          <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input type="tel" placeholder="Phone Number" value={phone} onChange={(e) => setPhone(e.target.value)} required className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-amber-500 focus:border-amber-500"/>
        </div>
        <div className="relative">
          <Home className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input type="text" placeholder="Delivery Address" value={address} onChange={(e) => setAddress(e.target.value)} required className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-amber-500 focus:border-amber-500"/>
        </div>
        <div>
          <button type="button" onClick={handleGetLocation} disabled={isGettingLocation || !!location} className="w-full flex justify-center items-center py-2 px-4 border rounded-lg text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300">
            {isGettingLocation ? <Loader2 className="h-5 w-5 mr-2 animate-spin" /> : location ? <CheckCircle className="h-5 w-5 mr-2" /> : <MapPin className="h-5 w-5 mr-2" />}
            {isGettingLocation ? 'Fetching...' : location ? 'Location Pinned!' : 'Pin Your Location'}
          </button>
          {locationError && <p className="text-red-500 text-xs mt-2">{locationError}</p>}
        </div>
        {signupError && <p className="text-red-500 text-sm text-center">{signupError}</p>}
        <button type="submit" disabled={!name || !phone || !address || !location} className="w-full flex justify-center items-center py-3 px-4 border rounded-lg text-base font-medium text-white bg-amber-600 hover:bg-amber-700 disabled:bg-amber-300">
            <UserPlus className="mr-2 h-5 w-5" />
            Sign Up & Continue
        </button>
      </form>
      <p className="text-center text-sm text-gray-600 mt-6">
        Already have an account?{' '}
        <button onClick={onSwitchToLogin} className="font-semibold text-indigo-600 hover:text-indigo-500">
          Login
        </button>
      </p>
    </div>
  );
};


const LoginScreen: React.FC<{switchToAdmin: () => void}> = ({ switchToAdmin }) => {
    const [authMode, setAuthMode] = useState<'login' | 'signup'>('login');

    return (
        <div className="max-w-md mx-auto bg-white p-8 rounded-2xl shadow-lg">
            {authMode === 'login' ? (
                <LoginView onSwitchToSignUp={() => setAuthMode('signup')} />
            ) : (
                <SignUpView onSwitchToLogin={() => setAuthMode('login')} />
            )}
            <div className="text-center mt-6 border-t pt-4">
                 <button 
                    onClick={switchToAdmin} 
                    className="text-sm font-semibold text-gray-600 hover:text-indigo-500 flex items-center justify-center w-full transition-colors"
                 >
                    <ShieldCheck className="mr-2 h-4 w-4" />
                    Admin Login
                 </button>
            </div>
        </div>
    )
}

export default LoginScreen;
